-- Language: en_US
insert or replace into EnglishText
    (Tag,                                                         Text)
values
    ("LOC_BELIEF_ONE_WITH_NATURE_NAME",                           "One with Nature"),
    ("LOC_BELIEF_ONE_WITH_NATURE_DL_DESCRIPTION",                 "+6 [ICON_GreatProphet] Great Prophet points per turn, and +3 [ICON_AMENITIES] Amenity for cities having at least one natural wonder tile."),
    ("LOC_BELIEF_RIVER_GODDESS_DL_DESCRIPTION",                   "Major adjacency bonus for Holy Site if next to a River. +2 [ICON_Amenities] Amenity and +2 [ICON_Housing] Housing to cities if they have a Holy Site district adjacent to a River. +2 [ICON_GreatProphet] Great Prophet points per turn if a city is located adjacent to a River."),
    ("LOC_BELIEF_GOD_OF_WAR_DL_DESCRIPTION",                      "Combat units receive +2 [ICON_Strength] combat strength when attack. Bonus [ICON_SCIENCE] Scienc equal to 40% of the base strength of each combat unit killed (on Standard Speed). Receive [ICON_GREATGENERAL] Great General points equal to 25% of the opposing unit's base strength (on Standard Speed) when a combat unit defeats a major or minor civilization's unit."),
    ("LOC_ABILITY_GOD_OF_WAR_GREAT_GENERAL_NAME",                 "Great General points"),
    ("LOC_ABILITY_GOD_OF_WAR_GREAT_GENERAL_DESCRIPTION",          "Receive [ICON_GREATGENERAL] Great General points when a combat unit defeats a major or minor civilization's unit equal to 25% of the opposing unit's strength (Standard Speed). (God of War Belief)"),
    ("LOC_GOD_OF_WAR_GREAT_COMBAT_STRENGTH_MODIFIER_PREVIEW_TEXT","God of War Belief"),
    ("LOC_BELIEF_MONUMENT_TO_THE_GODS_DL_DESCRIPTION",            "When chosen, receive a free Monument in your capital. Monument provides +1 [ICON_CULTURE] Culture and +10% [ICON_Culture] Culture to the city. May purchase Monument with [ICON_Faith] Faith."),
    ("LOC_BELIEF_FERTILITY_RITES_DL_DESCRIPTION",                 "When chosen, receive a free Granary in your capital. Granary provides +1 [ICON_FOOD] Food and +10% growth rate to the city. [ICON_Food] Food consumption of [ICON_Citizen] citizens is reduced by 0.3 in City with Granary. May purchase Granary with [ICON_Faith] Faith."),
    ("LOC_BELIEF_CITY_PATRON_GODDESS_DL_DESCRIPTION",             "When chosen, receive a builder unit in your [ICON_CAPITAL] Capital. +1 [ICON_FOOD] Food, +75% [ICON_Production] Production towards Districts in cities without a Specialty district."),
    ("LOC_BELIEF_MESSENGER_OF_THE_GODS_NAME",                     "Messenger of the Gods"),
    ("LOC_BELIEF_MESSENGER_OF_THE_GODS_DL_DESCRIPTION",           "When chosen, receive a Recon unit with one free promotion in your [ICON_Capital] Capital. +1 [ICON_Movement] Movement for all Recon Units."),
    ("LOC_BELIEF_GOD_OF_THE_OPEN_SKY_DL_DESCRIPTION",             "+1 [ICON_Production] Production and +1 [ICON_Culture] Culture from Pastures."),
    ("LOC_BELIEF_ORAL_TRADITION_DL_DESCRIPTION",                  "+1 [ICON_Food] Food and +1 [ICON_Culture] Culture from Plantations."),
    ("LOC_BELIEF_LADY_OF_THE_REEDS_AND_MARSHES_DL_DESCRIPTION",   "+1 [ICON_Production] Production from Grassland Floodplains. +1 [ICON_FOOD] Food from Plain Floodplains. +2 [ICON_Production] Production and +1 [ICON_Science] Science from Marsh."),-- Floodplain tiles no longer lower adjacent tiles' Appeal.
    ("LOC_BELIEF_GODDESS_OF_THE_HUNT_DL_DESCRIPTION",             "Camps over Luxury and Bonus resources provide +1 [ICON_Food] Food and +1 [ICON_Production] Production."),
    ("LOC_BELIEF_DIVINE_SPARK_DL_DESCRIPTION",                    "+3 corresponding [ICON_GREATPERSON] Great Person Points for each Districts. Your [ICON_CAPITAL] capital can build 1 more district than the [ICON_CITIZEN] Population limit allows."),
    ("LOC_BELIEF_STONE_CIRCLES_DL_DESCRIPTION",                   "Quarries provide +1 [ICON_Faith] Faith and +1 [ICON_SCIENCE] Science. Cities having Quarries provide +2 [ICON_GreatProphet] Great Prophet points per turn."),
    ("LOC_BELIEF_RELIGIOUS_IDOLS_DL_DESCRIPTION",                 "+1 [ICON_Faith] Faith and +1 [ICON_CULTURE] Culture from Mines over resources. +2 [ICON_GreatProphet] Great Prophet points per turn for cities having mines over resources."),
    ("LOC_BELIEF_EARTH_GODDESS_DL_DESCRIPTION",                   "+2 [ICON_Faith] Faith from tiles with Breathtaking Appeal. +1 [ICON_Faith] Faith from tiles with Charming Appeal. +2 [ICON_GreatProphet] Great Prophet points per turn if a city is located on a Charming tile, doubles for Breathtaking tile."),
    ("LOC_BELIEF_GODDESS_OF_FIRE_DL_DESCRIPTION",                 "Geothermal Fissures and improved Volcanic Soil provide +1 [ICON_FAITH] Faith and +1 [ICON_CULTURE] Culture. Cities having Geothermal Fissures, Volcanic Soil or Volcano (Volcanic Wonders included) tiles provide +3 [ICON_GreatProphet] Great Prophet points per turn."),
    ("LOC_BELIEF_THE_PEOPLE_OF_POLAR_NAME",                       "The People of Polar"),
    ("LOC_BELIEF_THE_PEOPLE_OF_POLAR_DL_DESCRIPTION",             "+1 [ICON_PRODUCTION] Production, +2 [ICON_GOLD] Gold to Improvements over resource on Tundra."),
    ("LOC_BELIEF_GODDESS_OF_THE_DESERT_NAME",                     "Goddess of the Desert"),
    ("LOC_BELIEF_GODDESS_OF_THE_DESERT_DL_DESCRIPTION",           "City centers provide +1 [ICON_Food] Food and +1 [ICON_Faith] Faith for each adjacent Desert or Desert Hills tile. Cities having Desert or Desert Hills tiles provide +2 [ICON_GreatProphet] Great Prophet points per turn."),
    ("LOC_BELIEF_RELIGIOUS_SETTLEMENTS_DL_DESCRIPTION",           "+25% [ICON_PRODUCTION] Production toward Settlers. +1 [ICON_MOVEMENT] Movement to Settlers. Gain 30 [ICON_GREATPROPHET] Great Prophet points and 4 extra tiles upon founding cities."),
    ("LOC_BELIEF_DANCE_OF_THE_AURORA_DL_DESCRIPTION",             "Holy Site districts get minor adjacency bonus from Tundra and Tundra Hills. Holy Site provides +1 [ICON_Food] Food and +1 [ICON_CULTURE] Culture to adjacent Tundra tiles. +2 [ICON_GreatProphet] Great Prophet point per turn if Holy Site is located on Tundra or Tundra Hills tiles."),
    ("LOC_BELIEF_DESERT_FOLKLORE_DL_DESCRIPTION",                 "Holy Site districts get standard adjacency bonus from Desert and Desert Hills. Holy Site provides +1 [ICON_Food] Food and +1 [ICON_Faith] Faith to all adjacent Desert tiles when not pillaged. +2 [ICON_GreatProphet] Great Prophet points per turn if Holy Site is located on Desert or Desert Hills tiles."),
    ("LOC_BELIEF_SACRED_PATH_DL_DESCRIPTION",                     "Holy Site districts get standard adjacency bonus from Rainforest. Holy Site provides +1 [ICON_Culture] Culture to all adjacent Rainforest tiles when not pillaged. +2 [ICON_GreatProphet] Great Prophet points per turn if Holy Site is adjacent to Rainforest tiles."),
    ("LOC_BELIEF_VOODOO_NAME",                                    "Voodoo"),
    ("LOC_BELIEF_VOODOO_DL_DESCRIPTION",                          "City centers provide +1 [ICON_Production] Production for each adjacent Rainforest tile, +1 [ICON_Culture] Culture from every two adjacent Rainforest tiles."),
    ("LOC_BELIEF_GODDESS_OF_FESTIVALS_DL_DESCRIPTION",            "Plantations provide +1 [ICON_Production] Production and +1 [ICON_FAITH] Faith. Cities having Plantations provide +2 [ICON_GreatProphet] Great Prophet points per turn."),
    ("LOC_BELIEF_TENGRI_NAME",                                    "Tengri"),
    ("LOC_BELIEF_TENGRI_DL_DESCRIPTION",                          "Pastures provide +1 [ICON_FOOD] Food and +1 [ICON_Faith] Faith. Cities having Pastures provide +2 [ICON_GreatProphet] Great Prophet points per turn."),
    ("LOC_BELIEF_GODDESS_OF_THE_HARVEST_DL_DESCRIPTION",          "Farms over resource provide +1 [ICON_Food] Food and +1 [ICON_Production] Production."),
    ("LOC_BELIEF_GOD_OF_THE_SEA_DL_DESCRIPTION",                  "Fishing Boats provide +1 [ICON_Food] Food. +2 [ICON_GOLD] Golds to Fishing Boats that inprove Luxury resources. Cities having Fishing Boats provide +2 [ICON_GreatProphet] Great Prophet points per turn."),
    ("LOC_BELIEF_OCEAN_MOTHER_DL_DESCRIPTION",                    "City center receive +1 [ICON_Food] Food and +1 [ICON_Faith] Faith from each adjacent Shallow Sea and Lake tile. +2 [ICON_GreatProphet] Great Prophet point per turn for cities adjacent to Shallow Sea. +1 [ICON_FOOD] Food to Shallow Sea and Lake tiles in city with a Holy Site district."),
    ("LOC_BELIEF_OCEAN_MOTHER_NAME",                              "Ocean Mother"),
    ("LOC_BELIEF_HD_DRUID_NAME",                                  "Druid"),
    ("LOC_BELIEF_HD_DRUID_DL_DESCRIPTION",                        "Forest tiles provide +1 [ICON_Food] Food. Rainforest tiles provide +1 [ICON_Production] Production."),
    ("LOC_BELIEF_PATHFINDER_OF_THE_WASTELAND_NAME",               "Pathfinder of the WasteLand"),
    ("LOC_BELIEF_PATHFINDER_OF_THE_WASTELAND_DESCRIPTION",        "+1 [ICON_Production] Production from flat Desert tiles. Additional +1 [ICON_Production] Production to Oasis. "),
    ("LOC_BELIEF_HD_MAZU_BELIEF_NAME",                            "Mazu Belief"),
    ("LOC_BELIEF_HD_MAZU_BELIEF_DL_DESCRIPTION",                  "Cities adjacent to Coasts get +2 [ICON_Production] Production and +2 [ICON_HOUSING] Housing. Harbor district provides +2 [ICON_PRODUCTION] Production. +1 [ICON_CULTURE] Culture to Fishing Boats adjacent to any district."), 
    ("LOC_BELIEF_FISHING_TRADITION_NAME",                         "Fishing Traidition"),
    ("LOC_BELIEF_FISHING_TRADITION_DL_DESCRIPTION",               "+1 [ICON_Production] Production to Fishing Boats. +1 [ICON_FOOD] Food to Fishing Boats over Bonus resource "),
    ("LOC_BELIEF_HD_GOD_KING_NAME",                               "God King"),
    ("LOC_BELIEF_HD_GOD_KING_DL_DESCRIPTION",                     "Palace provides +1 [ICON_FOOD] Food, +1 [ICON_PRODUCTION] Production, +1 [ICON_CULTURE] Culture, +1 [ICON_SCIENCE] Science, +1 [ICON_FAITH] Faith and +1 [ICON_GOLD] Gold. When chosen, receive a [ICON_CITIZEN] Citizen in your [ICON_CAPITAL] capital and a free [ICON_ENVOY] envoy. +1 [ICON_AMENITIES] Amenity and +1 [ICON_HOUSING] Housing in your capital."),
    ("LOC_BELIEF_GOD_OF_CRAFTSMEN_EXPANSION2_DESCRIPTION",        "+1 [ICON_Production] Production and +3 [ICON_Gold] Gold from improved Strategic resources. Reveals [ICON_RESOURCE_HORSES] Horses and [ICON_RESOURCE_IRON] Iron without the normal technology requirement. Properly improved Strategic resources provide an additional +1 per turn."),
    ("LOC_BELIEF_GOD_OF_THE_FORGE_DESCRIPTION",                   "+50% [ICON_PRODUCTION] Production toward Ancient, Classical and Medieval military units. Unit maintenance reduced by 1 [ICON_GOLD] Gold per turn, per unit. Receive 40% discount on Strategic resource costs for units."),
    ("LOC_BELIEF_HD_HERMES_NAME",                                 "Hermes"),
    ("LOC_BELIEF_HD_HERMES_DL_DESCRIPTION",                       "+1 [ICON_TradeRoute] Trade Route capacity and receive a free Trader in the capital. +1 [ICON_GOLD] Gold to all your Trade Routes."),
    ("LOC_BELIEF_HD_POSTERITY_OF_MOUNTAIN_NAME",                  "Posterity of Mountain"),
    ("LOC_BELIEF_HD_POSTERITY_OF_MOUNTAIN_DL_DESCRIPTION",        "Campus and Holy Site districts receive additional standard adjacency bonus from Mountains. Cities having Mountains provide +2 [ICON_GreatProphet] Great Prophet points per turn. Cities adjacent to Mountains receive +1 [ICON_Amenities] Amenity and +1 [ICON_Housing] Housing."),
    ("LOC_BELIEF_HD_SONG_OF_SIREN_NAME",                          "Song of Siren"),
    ("LOC_BELIEF_HD_SONG_OF_SIREN_DL_DESCRIPTION",                "+2 [ICON_Production] Production, +1 [ICON_GOLD] Gold from Reefs."),
    ("LOC_BELIEF_HD_UTAKI_NAME",                                  "Utaki"),
    ("LOC_BELIEF_HD_UTAKI_DL_DESCRIPTION",                        "+1 [ICON_FOOD] Food and +1 [ICON_PRODUCTION] Production from tiles adjacent to Harbor Districts."),
    ("LOC_BELIEF_HD_WOLF_GOD_NAME",                               "Lupercal"),
    ("LOC_BELIEF_HD_WOLF_GOD_DL_DESCRIPTION",                     "Camps over Luxury and Bonus resources provide +1 [ICON_CULTURE] Culture and +1 [ICON_Faith] Faith. Cities having Camps over Luxury or Bonus resources provide +2 [ICON_GreatProphet] Great Prophet points per turn."),
    ("LOC_BELIEF_HD_SUN_GOD_NAME",                                "Apollo"),
    ("LOC_BELIEF_HD_SUN_GOD_DL_DESCRIPTION",                      "Farms provide +1 [ICON_Food] Food. Cities having Farm over resource provide +2 [ICON_GreatProphet] Great Prophet points per turn."),
    ("LOC_BELIEF_SPARTA_SPIRIT_NAME",                             "Militarism"),
    ("LOC_BELIEF_SPARTA_SPIRIT_DESCRIPTION",                      "+50% [ICON_PRODUCTION] Production toward Ancient, Classical and Medieval military units. Receive 40% discount on Strategic resource costs for units."),
    ("LOC_BELIEF_TALE_OF_DWALVES_NAME",                           "El Dorado"),
    ("LOC_BELIEF_TALE_OF_DWALVES_DESCRIPTION",                    "+1 [ICON_FOOD] Food and +1 [ICON_HOUSING] Housing from Mines over resources. +2 [ICON_GOLD] Gold from all Mines."),
    ("LOC_BELIEF_MEGALITHIC_WORSHIP_NAME",                        "Tjukurpa"),
    ("LOC_BELIEF_MEGALITHIC_WORSHIP_DESCRIPTION",                 "Quarries provide +1 [ICON_Food] Food and +1 [ICON_Culture] Culture."),
    ("LOC_BELIEF_ILLUMINATORS_NAME",                              "Illuminators"),
    ("LOC_BELIEF_ILLUMINATORS_DESCRIPTION",                       "When chosen, receive a Recon unit with free promotion in your [ICON_Capital] Capital. +1 [ICON_Movement] Movement for all Recon Units. +5 [ICON_STRENGTH] Combat Strength for all units when fighting Barbarians. Gain 50 [ICON_FAITH] Faith when you clear a Barbarian Outpost. The unit that cleared the Barbarian Outpost heals +100 HP."),
    ("LOC_ABILITY_STARLIGHT_NAVIGATER_DESCRIPTION",              "+1 [ICON_MOVEMENT] Movement. +5 [ICON_STRENGTH] Combat Strength. Escorted units move at the same speed."),
    ("LOC_BELIEF_STARLIGHT_NAVIGATER_NAME",                       "Starlight Navigater"),
    ("LOC_BELIEF_STARLIGHT_NAVIGATER_DESCRIPTION",               "Coastal Capital grain a Nacal Raider unit with a free Promotion. Nacal Raider units +1 [ICON_MOVEMENT] Movement and +5 [ICON_STRENGTH] Combat Strength and share its [ICON_MOVEMENT] Movement with all units in the formation."),
    ("LOC_BELIEF_ITANG_NAME",                                    "Itang"),
    ("LOC_BELIEF_ITANG_DESCRIPTION",                             "City Centers gain +1 [ICON_PRODUCTION] Production for every adjacent Shallow Sea and Lake tile. City Centers gain +1 [ICON_CULTURE] Culture for every 2 adjacent Shallow Sea and Lake tiles. +1 [ICON_AMENITIES] Amenity to coastal cities.");
    -- ("LOC_BELIEF_HD_DIONYSIAN_MYSTERIES_NAME",                   "Dionysian Mysteries"),
    -- ("LOC_BELIEF_HD_DIONYSIAN_MYSTERIES_DESCRIPTION",            "When chosen, receive a free Cellar in your capital. Cellar provides +2 [ICON_FOOD] Food and +1 [ICON_AMENITIES] Amenity to the city. May purchase Cellar with [ICON_Faith] Faith.");

