-- Language: zh_Hans_CN
insert or replace into LocalizedText
    (Language,      Tag,                                                         Text)
values
    ("zh_Hans_CN",  "LOC_BELIEF_ONE_WITH_NATURE_NAME",                           "天人合一"),
    ("zh_Hans_CN",  "LOC_BELIEF_ONE_WITH_NATURE_DL_DESCRIPTION",                 "拥有自然奇观的城市+3 [ICON_AMENITIES] 宜居度，且每回合+6 [ICON_GreatProphet] 大预言家点数。"),
    ("zh_Hans_CN",  "LOC_BELIEF_RIVER_GODDESS_DL_DESCRIPTION",                   "与河流相邻时，圣地获得大量相邻加成。如果拥有与河流相邻的圣地区域，则城市+2 [ICON_Amenities] 宜居度、+2 [ICON_Housing] 住房。如城市市中心坐落在河边，则每回合+2 [ICON_GreatProphet] 大预言家点数。"),
    ("zh_Hans_CN",  "LOC_BELIEF_GOD_OF_WAR_DL_DESCRIPTION",                      "战斗单位攻击时+2 [ICON_Strength] 战斗力。每击杀1个战斗单位即可获得等于其战斗力40%的 [ICON_SCIENCE] 科技值（标准速度下）。战斗单位击杀主要和小型文明的单位时，获得等同于对方单位战斗力25%的 [ICON_GREATGENERAL] 大将军点数（标准速度下）。"),
    ("zh_Hans_CN",  "LOC_ABILITY_GOD_OF_WAR_GREAT_GENERAL_NAME",                 "大将军点数"),
    ("zh_Hans_CN",  "LOC_ABILITY_GOD_OF_WAR_GREAT_GENERAL_DESCRIPTION",          "战斗单位击杀主要和小型文明的单位时，获得等同于对方单位战斗力25%的 [ICON_GREATGENERAL] 大将军点数（标准速度下）。（战争之神）"),
    ("zh_Hans_CN",  "LOC_GOD_OF_WAR_GREAT_COMBAT_STRENGTH_MODIFIER_PREVIEW_TEXT","战争之神"),
    ("zh_Hans_CN",  "LOC_BELIEF_MONUMENT_TO_THE_GODS_DL_DESCRIPTION",            "选择后即可在首都中获得一个免费的纪念碑。纪念碑+1 [ICON_CULTURE] 文化值，给所在城市提供+10% [ICON_Culture] 文化值。可以使用 [ICON_Faith] 信仰值购买纪念碑。"),
    ("zh_Hans_CN",  "LOC_BELIEF_FERTILITY_RITES_DL_DESCRIPTION",                 "选择后即可在首都中获得一个免费的粮仓。粮仓+1 [ICON_FOOD] 食物。拥有粮仓的城市+10%余粮。粮仓可使城市每 [ICON_Citizen] 市民消耗的 [ICON_Food] 食物减少0.3。可以使用 [ICON_Faith] 信仰值购买粮仓。"),
    ("zh_Hans_CN",  "LOC_BELIEF_CITY_PATRON_GODDESS_DL_DESCRIPTION",             "选择后在首都中获得1个建造者单位。没有专业化区域的城市所有区域+1 [ICON_FOOD] 食物，建造区域+75%建造速度。"),
    ("zh_Hans_CN",  "LOC_BELIEF_MESSENGER_OF_THE_GODS_NAME",                     "神使"),
    ("zh_Hans_CN",  "LOC_BELIEF_MESSENGER_OF_THE_GODS_DL_DESCRIPTION",           "选择后即可在首都中获得1个有免费晋升的侦察单位。所有侦察类型的单位+1 [ICON_Movement] 移动力。"),
    ("zh_Hans_CN",  "LOC_BELIEF_GOD_OF_THE_OPEN_SKY_DL_DESCRIPTION",             "牧场+1 [ICON_Production] 生产力和 +1 [ICON_Culture] 文化值。"),
    ("zh_Hans_CN",  "LOC_BELIEF_ORAL_TRADITION_DL_DESCRIPTION",                  "种植园+1 [ICON_Food] 食物和+1 [ICON_Culture] 文化值。"),
    ("zh_Hans_CN",  "LOC_BELIEF_LADY_OF_THE_REEDS_AND_MARSHES_DL_DESCRIPTION",   "平原泛滥平原提供+1 [ICON_Food] 食物,草原泛滥平原提供+1 [ICON_Production] 生产力。沼泽提供+1 [ICON_Production] 生产力和+1 [ICON_Science] 科技值。"),-- 泛滥平原不再为相邻单元格-1魅力。
    ("zh_Hans_CN",  "LOC_BELIEF_GODDESS_OF_THE_HUNT_DL_DESCRIPTION",             "改良奢侈品资源和加成资源的营地+1 [ICON_Food] 食物和 +1 [ICON_Production] 生产力。"),
    ("zh_Hans_CN",  "LOC_BELIEF_DIVINE_SPARK_DL_DESCRIPTION",                    "每个区域提供+3对应 [ICON_GreatPerson] 伟人点数。首都可以无视 [ICON_CITIZEN] 人口限制额外建造1个区域。"),
    ("zh_Hans_CN",  "LOC_BELIEF_STONE_CIRCLES_DL_DESCRIPTION",                   "采石场+1 [ICON_SCIENCE] 科技值和+1 [ICON_Faith] 信仰值。如城市中有采石场，则每回合+2 [ICON_GreatProphet] 大预言家点数。"),
    ("zh_Hans_CN",  "LOC_BELIEF_RELIGIOUS_IDOLS_DL_DESCRIPTION",                 "改良资源的矿山+1 [ICON_CULTURE] 文化值和+1 [ICON_FAITH] 信仰值。如城市拥有改良资源的矿山，则每回合+2 [ICON_GreatProphet] 大预言家点数。"),
    ("zh_Hans_CN",  "LOC_BELIEF_EARTH_GODDESS_DL_DESCRIPTION",                   "魅力为惊艳的单元格提供的 [ICON_Faith] 信仰值+2。魅力为迷人的单元格提供的 [ICON_Faith] 信仰值+1。如城市市中心坐落在迷人单元格上，则每回合+2 [ICON_GreatProphet] 大预言家点数，惊艳则翻倍。"),
    ("zh_Hans_CN",  "LOC_BELIEF_GODDESS_OF_FIRE_DL_DESCRIPTION",                 "地热裂缝和已改良的火山土单元格提供+1 [ICON_CULTURE] 文化值和+1 [ICON_FAITH] 信仰值。每座拥有地热裂缝、火山土或火山（包括火山自然奇观）的城市提供+3 [ICON_GreatProphet] 大预言家点数。"),
    ("zh_Hans_CN",  "LOC_BELIEF_THE_PEOPLE_OF_POLAR_NAME",                       "极地子民"),
    ("zh_Hans_CN",  "LOC_BELIEF_THE_PEOPLE_OF_POLAR_DL_DESCRIPTION",             "冻土上改良资源的改良设施+1 [ICON_PRODUCTION] 生产力、+2 [ICON_GOLD] 金币。"),
    ("zh_Hans_CN",  "LOC_BELIEF_GODDESS_OF_THE_DESERT_NAME",                     "沙之女神"),
    ("zh_Hans_CN",  "LOC_BELIEF_GODDESS_OF_THE_DESERT_DL_DESCRIPTION",           "市中心每相邻1个沙漠或沙漠丘陵单元格，获得+1 [ICON_Food] 食物和+1 [ICON_Faith] 信仰值。如城市中有沙漠或沙漠丘陵，则每回合+2 [ICON_GreatProphet] 大预言家点数。"),
    ("zh_Hans_CN",  "LOC_BELIEF_RELIGIOUS_SETTLEMENTS_DL_DESCRIPTION",           "建造开拓者+25%建造速度。开拓者+1 [ICON_MOVEMENT] 移动力。创建城市时获得+30点 [ICON_GREATPROPHET] 大预言家点数和额外4个单元格。"),
    ("zh_Hans_CN",  "LOC_BELIEF_DANCE_OF_THE_AURORA_DL_DESCRIPTION",             "圣地从冻土和冻土丘陵获得少量相邻加成。圣地给相邻的冻土单元格+1 [ICON_Food] 食物、+1 [ICON_CULTURE] 文化值。若圣地位于冻土或冻土丘陵则每回合+2 [ICON_GreatProphet] 大预言家点数。"),
    ("zh_Hans_CN",  "LOC_BELIEF_DESERT_FOLKLORE_DL_DESCRIPTION",                 "圣地从沙漠和沙漠丘陵获得标准相邻加成。未被劫掠过的圣地给相邻的沙漠单元格+1 [ICON_Food] 食物和+1 [ICON_Faith] 信仰值。若圣地位于沙漠或沙漠丘陵则每回合+2 [ICON_GreatProphet] 大预言家点数。"),
    ("zh_Hans_CN",  "LOC_BELIEF_SACRED_PATH_DL_DESCRIPTION",                     "圣地从雨林获得标准相邻加成。未被劫掠过的圣地给相邻的雨林单元格+1 [ICON_Culture] 文化。若圣地相邻雨林则每回合+2 [ICON_GreatProphet] 大预言家点数。"),
